    private static func maskEmail(_ email: String) -> String {
        let parts = email.split(separator: "@", maxSplits: 1, omittingEmptySubsequences: false)
        guard parts.count == 2 else { return "[INVALID_EMAIL]" }
        let local = String(parts[0])
        let domain = String(parts[1])
        let maskedLocal: String
        if local.count <= 2 {
            maskedLocal = String(local.prefix(1)) + "*"
        } else {
            maskedLocal = String(local.prefix(1)) + String(repeating: "*", count: max(1, local.count - 2)) + String(local.suffix(1))
        }
        return "\(maskedLocal)@\(domain)"
    }

    private static func redactHeaders(_ headers: [String: String]?) -> [String: String]? {
        guard var headers else { return nil }
        let redactKeys = [
            "Authorization",
            "Proxy-Authorization",
            "X-API-Key",
            "X-Auth-Token",
            "X-Token",
            "Cookie",
            "Set-Cookie"
        ]
        for key in headers.keys {
            if redactKeys.contains(where: { $0.caseInsensitiveCompare(key) == .orderedSame }) {
                headers[key] = "[REDACTED]"
            }
        }
        return headers
    }

    private static func stripQuery(_ urlString: String) -> String {
