// MARK: - UIControl Swizzling for Tap Tracking

private extension UIControl {
    static var _swizzledSendAction: Bool = false

    static func swizzleSendActionIfNeeded() {
        guard !_swizzledSendAction else { return }
        _swizzledSendAction = true

        let cls: AnyClass = UIControl.self
        let original = #selector(UIControl.sendAction(_:to:for:))
        let swizzled = #selector(UIControl._ad_sendAction(_:to:for:))

        guard
            let originalMethod = class_getInstanceMethod(cls, original),
            let swizzledMethod = class_getInstanceMethod(cls, swizzled)
        else { return }

        method_exchangeImplementations(originalMethod, swizzledMethod)
    }

    @objc func _ad_sendAction(_ action: Selector, to target: Any?, for event: UIEvent?) {
        let controlType = String(describing: type(of: self))
        let actionName = NSStringFromSelector(action)
        let targetType = target.map { String(describing: type(of: $0 as AnyObject)) } ?? "nil"

        var meta: [String: Any?] = [
            "control": controlType,
            "action": actionName,
            "target": targetType
        ]

        if let btn = self as? UIButton {
            meta["title"] = btn.currentTitle
        } else if let sw = self as? UISwitch {
            meta["isOn"] = sw.isOn
        } else if let seg = self as? UISegmentedControl {
            meta["selectedSegment"] = seg.selectedSegmentIndex
        } else if let slider = self as? UISlider {
            meta["value"] = slider.value
        }

        AnalyticsDebug.trackInteraction(name: "UIControl.sendAction", screen: nil, element: nil, metadata: meta)

        _ad_sendAction(action, to: target, for: event)
    }
}